--- a/BCAzureStreamAnalytics/src/Test/ProductAnalyticsTests.Codeunit.al
+++ b/BCAzureStreamAnalytics/src/Test/ProductAnalyticsTests.Codeunit.al
@@ -44,6 +44,37 @@ codeunit 50101 "Product Analytics Tests"
             Error('BuildProductAnalyticsJson must include blocked products but returned empty array.');
     end;

+    [Test]
+    procedure BuildProductAnalyticsJsonUsesCorrectCategoryKey()
+    var
+        ProductAnalyticsLookup: Record "Product Analytics Lookup";
+        ProductAnalyticsHelper: Codeunit "Product Analytics Helper";
+        JsonResult: Text;
+        JsonArray: JsonArray;
+        JsonToken: JsonToken;
+        JsonObj: JsonObject;
+    begin
+        // [SCENARIO] BuildProductAnalyticsJson must use 'category' as the JSON key for the category field
+        DeleteAllProductAnalyticsData();
+
+        // [GIVEN] A Product Analytics record with a category value
+        ProductAnalyticsLookup.Init();
+        ProductAnalyticsLookup."Product No." := 'TESTCAT001';
+        ProductAnalyticsLookup."Product Name" := 'Category Key Test Product';
+        ProductAnalyticsLookup.Category := Enum::"Product Category"::Electronics;
+        ProductAnalyticsLookup.Insert();
+
+        // [WHEN] BuildProductAnalyticsJson is called
+        JsonResult := ProductAnalyticsHelper.BuildProductAnalyticsJson();
+
+        // [THEN] The first JSON object must contain the key 'category'
+        JsonArray.ReadFrom(JsonResult);
+        JsonArray.Get(0, JsonToken);
+        JsonObj := JsonToken.AsObject();
+        if not JsonObj.Contains('category') then
+            Error('JSON output must use ''category'' as the key name but it was not found.');
+    end;
+
     local procedure DeleteAllProductAnalyticsData()
     var
         ProductAnalyticsLookup: Record "Product Analytics Lookup";

